import { useEffect, useMemo, useState } from 'react';

// Option A: the options never change, so hoist them out of the component.
const OPTIONS = { include: 'posts' } as const;

function Profile({ userId }: { userId: string }) {
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    let active = true;
    fetchUser(userId, OPTIONS).then(u => { if (active) setUser(u); });
    return () => { active = false; };
  }, [userId]); // OPTIONS is stable, no need to list it

  return <div>{user?.name}</div>;
}

// Option B: if options really are dynamic, memoize by their primitive contents.
function ProfileDynamic({ userId, include }: { userId: string; include: string }) {
  const [user, setUser] = useState<User | null>(null);
  const options = useMemo(() => ({ include }), [include]);

  useEffect(() => {
    let active = true;
    fetchUser(userId, options).then(u => { if (active) setUser(u); });
    return () => { active = false; };
  }, [userId, options]);

  return <div>{user?.name}</div>;
}

import { memo, useCallback, useState } from 'react';
import { useVirtualizer } from '@tanstack/react-virtual';
import { useRef } from 'react';

interface Item { id: string; label: string; }

const Row = memo(function Row({ item, onSelect }: { item: Item; onSelect: (id: string) => void }) {
  return (
    <div onClick={() => onSelect(item.id)} style={{ padding: 8 }}>
      {item.label}
    </div>
  );
});

export function BigList({ items }: { items: Item[] }) {
  const [selected, setSelected] = useState<string | null>(null);
  const parentRef = useRef<HTMLDivElement>(null);

  // Stable identity so memo'd rows do not re-render when selection changes.
  const onSelect = useCallback((id: string) => setSelected(id), []);

  const virtualizer = useVirtualizer({
    count: items.length,
    getScrollElement: () => parentRef.current,
    estimateSize: () => 36,
    overscan: 8,
  });

  return (
    <div ref={parentRef} style={{ height: 600, overflow: 'auto' }}>
      <div style={{ height: virtualizer.getTotalSize(), position: 'relative' }}>
        {virtualizer.getVirtualItems().map(v => (
          <div
            key={items[v.index].id}
            style={{ position: 'absolute', top: 0, transform: `translateY(${v.start}px)`, width: '100%' }}
          >
            <Row item={items[v.index]} onSelect={onSelect} />
          </div>
        ))}
      </div>
    </div>
  );
}
